import { useState, useEffect, useCallback, useMemo } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import ExportBar from '../components/ExportBar';
import usePageTitle from '../hooks/usePageTitle';
import s from './ArbitragePage.module.css';

const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
};

const TYPE_COLORS = {
  statistical: T.blue, pairs: T.purple, triangular: T.amber, cross_market: T.green,
};

function fmt(val, decimals = 2) {
  if (val == null || isNaN(val)) return '--';
  return Number(val).toFixed(decimals);
}

function fmtPct(val) {
  if (val == null || isNaN(val)) return '--';
  return `${(Number(val) * 100).toFixed(2)}%`;
}

export default function ArbitragePage() {
  usePageTitle('Arbitrage');
  const [data, setData] = useState(null);
  const [spreads, setSpreads] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [typeFilter, setTypeFilter] = useState('all');
  const [minZScore, setMinZScore] = useState('');
  const [sortBy, setSortBy] = useState('z_score');
  const [sortDir, setSortDir] = useState('desc');
  const [activeTab, setActiveTab] = useState('opportunities');
  const [spreadSortBy, setSpreadSortBy] = useState('spread_bps');
  const [spreadSortDir, setSpreadSortDir] = useState('desc');

  const fetchData = useCallback(async () => {
    try {
      const [oppRes, spreadRes] = await Promise.allSettled([
        fetch(`${getApiBase()}/arbitrage/opportunities`).then(r => {
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          return r.json();
        }),
        fetch(`${getApiBase()}/arbitrage/spreads`).then(r => {
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          return r.json();
        }),
      ]);

      if (oppRes.status === 'fulfilled') {
        setData(oppRes.value);
      } else {
        setError(oppRes.reason?.message || 'Failed to load opportunities');
      }

      if (spreadRes.status === 'fulfilled') {
        setSpreads(spreadRes.value);
      }

      if (oppRes.status === 'fulfilled') setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const iv = setInterval(fetchData, 10000);
    return () => clearInterval(iv);
  }, [fetchData]);

  const opps = data?.opportunities || [];
  const spreadList = spreads?.spreads || spreads?.data || (Array.isArray(spreads) ? spreads : []);

  const types = useMemo(() => {
    const set = new Set(opps.map(o => o.arb_type).filter(Boolean));
    return ['all', ...Array.from(set).sort()];
  }, [opps]);

  const filtered = useMemo(() => {
    let list = [...opps];
    if (typeFilter !== 'all') list = list.filter(o => o.arb_type === typeFilter);
    if (minZScore) list = list.filter(o => Math.abs(o.z_score ?? 0) >= Number(minZScore));
    list.sort((a, b) => {
      const av = a[sortBy] ?? 0, bv = b[sortBy] ?? 0;
      return sortDir === 'desc' ? bv - av : av - bv;
    });
    return list;
  }, [opps, typeFilter, minZScore, sortBy, sortDir]);

  const sortedSpreads = useMemo(() => {
    const list = [...spreadList];
    list.sort((a, b) => {
      const av = a[spreadSortBy] ?? 0, bv = b[spreadSortBy] ?? 0;
      return spreadSortDir === 'desc' ? bv - av : av - bv;
    });
    return list;
  }, [spreadList, spreadSortBy, spreadSortDir]);

  const stats = useMemo(() => {
    const total = opps.length;
    const avgSpread = total ? (opps.reduce((s, o) => s + (o.spread_bps || 0), 0) / total).toFixed(1) : '--';
    const maxZ = total ? Math.max(...opps.map(o => Math.abs(o.z_score || 0))).toFixed(2) : '--';
    const highConf = opps.filter(o => (o.confidence || 0) >= 0.7).length;
    return { total, avgSpread, maxZ, highConf };
  }, [opps]);

  const spreadStats = useMemo(() => {
    const total = spreadList.length;
    const avgSpread = total ? (spreadList.reduce((s, o) => s + (o.spread_bps || o.spread || 0), 0) / total).toFixed(1) : '--';
    const widest = total ? Math.max(...spreadList.map(o => o.spread_bps || o.spread || 0)).toFixed(1) : '--';
    const tightest = total ? Math.min(...spreadList.map(o => o.spread_bps || o.spread || 0)).toFixed(1) : '--';
    return { total, avgSpread, widest, tightest };
  }, [spreadList]);

  const toggleSort = (col) => {
    if (sortBy === col) setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSortBy(col); setSortDir('desc'); }
  };

  const toggleSpreadSort = (col) => {
    if (spreadSortBy === col) setSpreadSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSpreadSortBy(col); setSpreadSortDir('desc'); }
  };

  const sortArrow = (col) => sortBy === col ? (sortDir === 'desc' ? ' \u25BC' : ' \u25B2') : '';
  const spreadSortArrow = (col) => spreadSortBy === col ? (spreadSortDir === 'desc' ? ' \u25BC' : ' \u25B2') : '';

  if (loading) {
    return (
      <div className={s.loadingWrap}>
        Scanning arbitrage opportunities...
      </div>
    );
  }

  return (
    <div className={s.pageRoot}>
      <h1 className={s.title}>Arbitrage Scanner</h1>
      <p className={s.subtitle}>
        Cross-market arbitrage opportunities, spreads, statistical pairs, and triangular arb
      </p>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>Error: {error}</div>
        </GlassPanel>
      )}

      {/* Tab Switcher */}
      <div style={{
        display: 'flex', gap: 4, marginBottom: 20,
      }}>
        {[
          { key: 'opportunities', label: `Opportunities (${opps.length})` },
          { key: 'spreads', label: `Spreads (${spreadList.length})` },
        ].map(t => (
          <button key={t.key} onClick={() => setActiveTab(t.key)} style={{
            fontFamily: "var(--font-mono, 'JetBrains Mono', monospace)",
            fontSize: 13, fontWeight: 600, padding: '8px 16px', borderRadius: 6,
            cursor: 'pointer', border: 'none', transition: 'all 0.15s',
            background: activeTab === t.key ? 'rgba(96,165,250,0.125)' : 'transparent',
            color: activeTab === t.key ? 'var(--color-blue, #60A5FA)' : 'var(--color-text-secondary, #90A3AF)',
          }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* ========== OPPORTUNITIES TAB ========== */}
      {activeTab === 'opportunities' && (
        <>
          {/* Stats */}
          <div className={s.statsGrid}>
            <StatCard label="Total Opportunities" value={stats.total} color={T.blue} />
            <StatCard label="Avg Spread (bps)" value={stats.avgSpread} color={T.green} />
            <StatCard label="Highest Z-Score" value={stats.maxZ} color={T.purple} />
            <StatCard label="High Confidence" value={stats.highConf} color={T.amber} />
          </div>

          {/* Filters */}
          <div className={s.filterRow}>
            <label className={s.filterLabel}>
              Type
              <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className={s.filterSelect}>
                {types.map(t => <option key={t} value={t}>{t === 'all' ? 'All Types' : t.replace(/_/g, ' ')}</option>)}
              </select>
            </label>
            <label className={s.filterLabel}>
              Min |Z-Score|
              <input type="number" step="0.1" value={minZScore} onChange={e => setMinZScore(e.target.value)}
                placeholder="e.g. 2.0" className={s.filterInput} />
            </label>
            <button onClick={fetchData} className={s.refreshBtn}>
              Refresh
            </button>
          </div>

          {/* Table */}
          {filtered.length > 0 ? (
            <>
              <ExportBar data={filtered} filename="arbitrage-opportunities" columns={['Pair', 'Type', 'Spread (bps)', 'Z-Score', 'Direction', 'Confidence', 'Expected Profit']} />
              <GlassPanel padding={0} className={s.tableWrap}>
                <table className={s.table}>
                  <thead>
                    <tr className={s.theadRow}>
                      {[
                        { key: 'pair', label: 'Pair' },
                        { key: 'arb_type', label: 'Type' },
                        { key: 'spread_bps', label: 'Spread (bps)' },
                        { key: 'z_score', label: 'Z-Score' },
                        { key: 'direction', label: 'Direction' },
                        { key: 'confidence', label: 'Confidence' },
                        { key: 'expected_profit_bps', label: 'Exp Profit (bps)' },
                      ].map(col => (
                        <th key={col.key} onClick={() => toggleSort(col.key)} className={s.th}>
                          {col.label}{sortArrow(col.key)}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.map((o, i) => {
                      const typeColor = TYPE_COLORS[o.arb_type] || T.blue;
                      return (
                        <tr key={i} style={{ borderBottom: i < filtered.length - 1 ? '1px solid var(--color-border, #1F2A37)' : 'none' }}>
                          <td className={s.tdPair}>
                            {Array.isArray(o.pair) ? o.pair.join(' / ') : o.pair || '--'}
                          </td>
                          <td className={s.td}>
                            <span className={s.badge} style={{
                              background: typeColor + '18', color: typeColor,
                            }}>
                              {(o.arb_type || '--').replace(/_/g, ' ')}
                            </span>
                          </td>
                          <td className={s.tdSpread}>{fmt(o.spread_bps, 1)}</td>
                          <td className={s.td} style={{ color: Math.abs(o.z_score || 0) >= 2 ? T.green : T.text, fontWeight: 600 }}>
                            {fmt(o.z_score, 2)}
                          </td>
                          <td className={s.td}>
                            <span className={s.directionBadge} style={{
                              background: o.direction === 'LONG' ? T.green + '18' : T.red + '18',
                              color: o.direction === 'LONG' ? T.green : T.red,
                            }}>
                              {o.direction || '--'}
                            </span>
                          </td>
                          <td className={s.td}>
                            <div className={s.confWrap}>
                              <div className={s.confTrack}>
                                <div className={s.confFill} style={{
                                  width: `${Math.min(100, (o.confidence || 0) * 100)}%`,
                                  background: (o.confidence || 0) >= 0.7 ? T.green : (o.confidence || 0) >= 0.4 ? T.amber : T.red,
                                }} />
                              </div>
                              <span className={s.confValue}>{fmt(o.confidence, 2)}</span>
                            </div>
                          </td>
                          <td className={s.tdProfit}>{fmt(o.expected_profit_bps, 1)}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </GlassPanel>
            </>
          ) : (
            <GlassPanel className={s.emptyWrap}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke={T.textSec} strokeWidth="1.5">
                <path d="M16 3h5v5M8 3H3v5M3 16v5h5M21 16v5h-5M12 8v8M8 12h8" />
              </svg>
              <div className={s.emptyTitle}>No arbitrage opportunities detected</div>
              <div className={s.emptySub}>Opportunities refresh every 10 seconds</div>
            </GlassPanel>
          )}
        </>
      )}

      {/* ========== SPREADS TAB ========== */}
      {activeTab === 'spreads' && (
        <>
          {/* Spread Stats */}
          <div className={s.statsGrid}>
            <StatCard label="Total Spreads" value={spreadStats.total} color={T.blue} />
            <StatCard label="Avg Spread (bps)" value={spreadStats.avgSpread} color={T.green} />
            <StatCard label="Widest (bps)" value={spreadStats.widest} color={T.red} />
            <StatCard label="Tightest (bps)" value={spreadStats.tightest} color={T.purple} />
          </div>

          <div className={s.filterRow}>
            <button onClick={fetchData} className={s.refreshBtn}>
              Refresh Spreads
            </button>
          </div>

          {sortedSpreads.length > 0 ? (
            <>
              <ExportBar data={sortedSpreads} filename="arbitrage-spreads" columns={['Pair', 'Spread (bps)', 'Bid', 'Ask', 'Mid', 'Volume', 'Timestamp']} />
              <GlassPanel padding={0} className={s.tableWrap}>
                <table className={s.table}>
                  <thead>
                    <tr className={s.theadRow}>
                      {[
                        { key: 'pair', label: 'Pair / Instrument' },
                        { key: 'spread_bps', label: 'Spread (bps)' },
                        { key: 'bid', label: 'Bid' },
                        { key: 'ask', label: 'Ask' },
                        { key: 'mid', label: 'Mid' },
                        { key: 'volume', label: 'Volume' },
                        { key: 'correlation', label: 'Correlation' },
                        { key: 'half_life', label: 'Half-Life' },
                      ].map(col => (
                        <th key={col.key} onClick={() => toggleSpreadSort(col.key)} className={s.th}>
                          {col.label}{spreadSortArrow(col.key)}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {sortedSpreads.map((sp, i) => {
                      const spreadVal = sp.spread_bps || sp.spread || 0;
                      const spreadColor = spreadVal >= 50 ? T.red : spreadVal >= 20 ? T.amber : T.green;
                      return (
                        <tr key={i} style={{ borderBottom: i < sortedSpreads.length - 1 ? '1px solid var(--color-border, #1F2A37)' : 'none' }}>
                          <td className={s.tdPair}>
                            {Array.isArray(sp.pair) ? sp.pair.join(' / ') : sp.pair || sp.instrument || sp.symbol || '--'}
                          </td>
                          <td className={s.td} style={{ color: spreadColor, fontWeight: 700 }}>
                            {fmt(spreadVal, 1)}
                          </td>
                          <td className={s.td} style={{ color: T.text, fontWeight: 600 }}>
                            {sp.bid != null ? fmt(sp.bid, 4) : '--'}
                          </td>
                          <td className={s.td} style={{ color: T.text, fontWeight: 600 }}>
                            {sp.ask != null ? fmt(sp.ask, 4) : '--'}
                          </td>
                          <td className={s.td} style={{ color: T.text }}>
                            {sp.mid != null ? fmt(sp.mid, 4) : '--'}
                          </td>
                          <td className={s.td} style={{ color: T.textSec }}>
                            {sp.volume != null ? Number(sp.volume).toLocaleString() : '--'}
                          </td>
                          <td className={s.td}>
                            {sp.correlation != null ? (
                              <div className={s.confWrap}>
                                <div className={s.confTrack}>
                                  <div className={s.confFill} style={{
                                    width: `${Math.min(100, Math.abs(sp.correlation) * 100)}%`,
                                    background: Math.abs(sp.correlation) >= 0.8 ? T.green : Math.abs(sp.correlation) >= 0.5 ? T.amber : T.red,
                                  }} />
                                </div>
                                <span className={s.confValue}>{fmt(sp.correlation, 3)}</span>
                              </div>
                            ) : '--'}
                          </td>
                          <td className={s.td} style={{ color: T.textSec }}>
                            {sp.half_life != null ? `${fmt(sp.half_life, 1)}d` : '--'}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </GlassPanel>
            </>
          ) : (
            <GlassPanel className={s.emptyWrap}>
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke={T.textSec} strokeWidth="1.5">
                <path d="M3 3v18h18M7 14l4-4 4 4 4-4" />
              </svg>
              <div className={s.emptyTitle}>No spread data available</div>
              <div className={s.emptySub}>Spread data refreshes every 10 seconds</div>
            </GlassPanel>
          )}
        </>
      )}
    </div>
  );
}
